                float4 baseCol = SampleTriplanar(_BaseTex, worldPos, n, _BaseScale);

                // Detail sampling with UV warp
                // compute a detail UV based on world pos, warp it by noise
                float2 dUV = worldPos.xz * _DetailScale;
                dUV = WarpUV(dUV, worldPos);
                // For detail use triplanar as well to keep consistency on slopes
                float4 detailCol = SampleTriplanar(_DetailTex, float3(dUV,0), n, 1.0);

                // Procedural mask from noise to blend detail (tiled sampling)
                float mask = tex2D(_NoiseTex, TileUV(worldPos.xz * 0.5)).r;
                float blendMask = smoothstep(0.4, 0.7, mask) * _DetailStrength;

                float4 result = lerp(baseCol, detailCol * _DetailTint, blendMask);
                return result;
            }
            ENDCG
        }
    }
    FallBack "Diffuse"
}

