Shader "Custom/TriplanarDetailUnlit" {
    Properties {
        _BaseTex("Base Texture", 2D) = "white" {}
        _DetailTex("Detail Texture", 2D) = "white" {}
        _NoiseTex("Noise Texture", 2D) = "white" {}
        _BaseScale("Base Scale", Float) = 0.08
        _DetailScale("Detail Scale", Float) = 4.0
        _WarpScale("Warp Scale", Float) = 0.01
        _WarpStrength("Warp Strength", Float) = 0.02
        _DetailTint("Detail Tint", Color) = (1,1,1,1)
        _DetailStrength("Detail Strength", Range(0,1)) = 0.6
    }
    SubShader {
        Tags { "RenderType" = "Opaque" }
        LOD 200
        Pass {
            CGPROGRAM
            #pragma vertex vert
            #pragma fragment frag
            #include "UnityCG.cginc"

            sampler2D _BaseTex;
            sampler2D _DetailTex;
            sampler2D _NoiseTex;
            float2 _NoiseOffset;
            float _BaseScale;
            float _DetailScale;
            float _WarpScale;
            float _WarpStrength;
            float4 _DetailTint;
            float _DetailStrength;

            struct appdata {
                float4 vertex : POSITION;
                float3 normal : NORMAL;
            };

            struct v2f {
                float4 pos : SV_POSITION;
                float3 worldPos : TEXCOORD0;
                float3 worldNormal : TEXCOORD1;
            };

            v2f vert(appdata v) {
                v2f o;
                o.pos = UnityObjectToClipPos(v.vertex);
                o.worldPos = mul(unity_ObjectToWorld, v.vertex).xyz;
                o.worldNormal = UnityObjectToWorldNormal(v.normal);
                return o;
            }

            // Tile UV helper: keeps coords inside 0..1 even for negative positions
            float2 TileUV(float2 uv) { return uv - floor(uv + 1e-5); }

            // Triplanar sampling using tiled world-space UVs
            float4 SampleTriplanar(sampler2D tex, float3 worldPos, float3 normal, float scale)
            {
                float3 blend = abs(normal);
                blend = max(blend, 0.0001);
                blend /= (blend.x + blend.y + blend.z);

                float2 uvX = TileUV(worldPos.yz * scale);
                float2 uvY = TileUV(worldPos.xz * scale);
                float2 uvZ = TileUV(worldPos.xy * scale);

                float4 sx = tex2D(tex, uvX);
                float4 sy = tex2D(tex, uvY);
                float4 sz = tex2D(tex, uvZ);

                return sx * blend.x + sy * blend.y + sz * blend.z;
            }

            float2 WarpUV(float2 uv, float3 worldPos)
            {
                float2 samplePos = TileUV(worldPos.xz * _WarpScale + _NoiseOffset);
                float2 n = tex2D(_NoiseTex, samplePos).rg * 2.0 - 1.0;
                return uv + n * _WarpStrength;
            }

            fixed4 frag(v2f i) : SV_Target
            {
                float3 worldPos = i.worldPos;
                float3 n = normalize(i.worldNormal);

                // Base (large-scale) sampling
                float4 baseCol = SampleTriplanar(_BaseTex, worldPos, n, _BaseScale);

                // Detail sampling with UV warp
                // compute a detail UV based on world pos, warp it by noise
                float2 dUV = worldPos.xz * _DetailScale;
                dUV = WarpUV(dUV, worldPos);
                // For detail use triplanar as well to keep consistency on slopes
                float4 detailCol = SampleTriplanar(_DetailTex, float3(dUV,0), n, 1.0);

                // Procedural mask from noise to blend detail (tiled sampling)
                float mask = tex2D(_NoiseTex, TileUV(worldPos.xz * 0.5 + _NoiseOffset)).r;
                float blendMask = smoothstep(0.4, 0.7, mask) * _DetailStrength;

                float4 result = lerp(baseCol, detailCol * _DetailTint, blendMask);
                return result;
            }
            ENDCG
        }
    }
    FallBack "Diffuse"
}

using UnityEngine;

// Attach to the terrain/chunk parent or a GameObject with a Renderer.
// It will create/assign a material using the Custom/TriplanarDetailUnlit shader,
// generate a small noise texture and set shader parameters so you can test the effect.
public class TextureEnhancer : MonoBehaviour
{
    public Material targetMaterial;
    public Renderer targetRenderer;
    [Header("Per-Chunk Offsets")]
    [Tooltip("Root transform containing chunk renderers. Defaults to this GameObject.")]
    public Transform chunksRoot;
    [Tooltip("Scale applied to world position to produce offset; larger values change offset more per chunk.")]
    public float noiseOffsetScale = 0.01f;
    [Tooltip("Assign unique _NoiseOffset to each child renderer using MaterialPropertyBlock.")]
    public bool assignPerChildOffsets = true;
    [Tooltip("If true, reassign offsets every frame (useful if chunks are spawned dynamically).")]
    public bool updateEveryFrame = false;

    [Header("Noise")]
    public int noiseSize = 256;
    public float noiseFrequency = 1f;
    public int seed = 0;

    [Header("Scales")]
    public float baseScale = 0.08f;
    public float detailScale = 4f;
    public float warpScale = 0.01f;
    public float warpStrength = 0.02f;

    [Header("Detail")]
    public Color detailTint = Color.white;
    [Range(0f,1f)] public float detailStrength = 0.6f;

    void Start()
    {
        if (targetMaterial == null)
        {
            Shader s = Shader.Find("Custom/TriplanarDetailUnlit");
            if (s != null)
                targetMaterial = new Material(s);
            else
                Debug.LogError("Shader Custom/TriplanarDetailUnlit not found.");
        }

        if (targetRenderer == null)
            targetRenderer = GetComponent<Renderer>();

        if (targetMaterial != null)
        {
            var noise = GenerateNoise(noiseSize, noiseFrequency, seed);
            noise.wrapMode = TextureWrapMode.Repeat;
            targetMaterial.SetTexture("_NoiseTex", noise);
            targetMaterial.SetFloat("_BaseScale", baseScale);
            targetMaterial.SetFloat("_DetailScale", detailScale);
            targetMaterial.SetFloat("_WarpScale", warpScale);
            targetMaterial.SetFloat("_WarpStrength", warpStrength);
            targetMaterial.SetColor("_DetailTint", detailTint);
            targetMaterial.SetFloat("_DetailStrength", detailStrength);

            if (targetRenderer != null)
            {
                // assign as sharedMaterial so you can edit in play mode and see changes
                targetRenderer.sharedMaterial = targetMaterial;
                // assign per-child offsets if requested
                if (assignPerChildOffsets)
                {
                    if (chunksRoot == null) chunksRoot = this.transform;
                    AssignOffsetsToChildren();
                }
            }
        }
    }

    void Update()
    {
        if (assignPerChildOffsets && updateEveryFrame)
            AssignOffsetsToChildren();
    }

    void AssignOffsetsToChildren()
    {
        if (chunksRoot == null) return;
        var renderers = chunksRoot.GetComponentsInChildren<Renderer>(true);
        foreach (var r in renderers)
        {
            // compute a stable offset based on world position + seed
            float ox = Mathf.Repeat((r.transform.position.x * noiseOffsetScale) + (seed * 0.137f), 1f);
            float oy = Mathf.Repeat((r.transform.position.z * noiseOffsetScale) + (seed * 0.421f), 1f);
            var mpb = new MaterialPropertyBlock();
            r.GetPropertyBlock(mpb);
            mpb.SetVector("_NoiseOffset", new Vector4(ox, oy, 0f, 0f));
            r.SetPropertyBlock(mpb);
        }
    }

    Texture2D GenerateNoise(int size, float frequency, int seed)
    {
        var tex = new Texture2D(size, size, TextureFormat.RGBA32, false);
        var rng = new System.Random(seed);
        float ox = (float)rng.NextDouble() * 1000f;
        float oy = (float)rng.NextDouble() * 1000f;

        for (int y = 0; y < size; y++)
        {
            for (int x = 0; x < size; x++)
            {
                float nx = (float)x / size * frequency + ox;
                float ny = (float)y / size * frequency + oy;
                float v = Mathf.PerlinNoise(nx, ny);
                tex.SetPixel(x, y, new Color(v, v, v, 1f));
            }
        }
        tex.Apply();
        return tex;
    }
}

